import sys

class Solution:
    def __init__(self):
        self.maze: list[list[int]] = []
        self.rows: int = 0
        self.cols: int = 0
        self.path: list[tuple[int, int]] = []

    def solve(self) -> bool:
        if not self.maze or self.maze[0][0] == 1 or self.maze[self.rows-1][self.cols-1] == 1:
            return False

        visited = [[False]*self.cols for _ in range(self.rows)]
        self.path = []

        def dfs(r, c):
            if r == self.rows - 1 and c == self.cols - 1:
                self.path.append((r, c))
                return True

            visited[r][c] = True
            self.path.append((r, c))

            for dr, dc in [(1, 0), (0, 1), (-1, 0), (0, -1)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < self.rows and 0 <= nc < self.cols:
                    if not visited[nr][nc] and self.maze[nr][nc] == 0:
                        if dfs(nr, nc):
                            return True

            self.path.pop()
            visited[r][c] = False
            return False

        return dfs(0, 0)

if __name__ == '__main__':
    tokens = sys.stdin.read().split()
    if not tokens:
        sys.exit(0)
    R = int(tokens[0])
    C = int(tokens[1])
    sol = Solution()
    sol.rows = R
    sol.cols = C
    sol.maze = []
    idx = 2
    for _ in range(R):
        row = [int(x) for x in tokens[idx:idx+C]]
        sol.maze.append(row)
        idx += C
    if sol.solve():
        out = "PATH"
        for p in sol.path:
            out += f" ({p[0]},{p[1]})"
        print(out)
    else:
        print("NO PATH")

