#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> maze;
    int rows, cols;
    vector<pair<int, int>> path;

    bool dfs(int r, int c, vector<vector<bool>>& visited) {
        if (r == rows - 1 && c == cols - 1) {
            path.push_back({r, c});
            return true;
        }
        visited[r][c] = true;
        path.push_back({r, c});

        int dr[] = {1, 0, -1, 0};
        int dc[] = {0, 1, 0, -1};
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i];
            int nc = c + dc[i];
            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols) {
                if (!visited[nr][nc] && maze[nr][nc] == 0) {
                    if (dfs(nr, nc, visited)) return true;
                } 
            }
        }

        path.pop_back();
        visited[r][c] = false;
        return false;
    }

    bool solve() {
        if (maze.empty() || maze[0][0] == 1 || maze[rows-1][cols-1] == 1) {
            return false;
        }
        path.clear();
        vector<vector<bool>> visited(rows, vector<bool>(cols, false));
        return dfs(0, 0, visited);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int r, c;
    if (!(cin >> r >> c)) return 0;
    Solution sol;
    sol.rows = r;
    sol.cols = c;
    sol.maze.assign(r, vector<int>(c));
    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            cin >> sol.maze[i][j];
        }
    }
    if (sol.solve()) {
        cout << "PATH";
        for (const auto& p : sol.path) {
            cout << " (" << p.first << "," << p.second << ")";
        }
        cout << "\n";
    } else {
        cout << "NO PATH\n";
    }
    return 0;
}
